using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class EchoTools
{
    [McpServerTool, Description("Echoes back the provided message with a timestamp.")]
    public static string Echo(
        [Description("The message to echo back")] string message)
    {
        return $"[{DateTime.UtcNow:O}] {message}";
    }

    [McpServerTool, Description("Returns the current server time in UTC.")]
    public static string GetServerTime()
    {
        return DateTime.UtcNow.ToString("O");
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpHttpServer.Resources;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the application configuration settings.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "Production",
            Version = "1.0.0",
            Features = new { DarkMode = true, BetaAccess = false },
            MaxRequestsPerMinute = 60
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/endpoints", Name = "Service Endpoints",
        MimeType = "application/json"),
     Description("Returns the list of available service endpoints.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Name = "API", Url = "https://api.example.com", Status = "active" },
            new { Name = "Auth", Url = "https://auth.example.com", Status = "active" },
            new { Name = "Storage", Url = "https://storage.example.com", Status = "maintenance" }
        };

        return JsonSerializer.Serialize(endpoints, new JsonSerializerOptions { WriteIndented = true });
    }
}

